import {Component, Input, OnInit, Output, EventEmitter, SimpleChanges, OnChanges} from '@angular/core';
import * as $ from 'jquery';
import { Constants } from 'src/app/constant/Constants';

@Component({
  selector: 'app-popup-confirm-apply-common',
  templateUrl: './popup-confirm.component.html',
  styleUrls: ['./popup-confirm.component.scss']
})

export class PopupConfirmApplyComponentCommon implements OnInit, OnChanges {
  @Output() validate = new EventEmitter();
  @Output() onClose = new EventEmitter();
  cancelLbl = Constants.cancelLbl;
  yesLbl = Constants.yesLbl;
  confirmMessage: any;
  noticeLbl = Constants.noticeLbl;
  item: any;
  isRedirect: any;
  constructor() {
    // this.closePopup();
  }

  ngOnInit(): void {
    // this.closePopup();
  }
  ngOnChanges(changes: SimpleChanges) {
    // this.closePopup();
  }

  openPopup(jobItem: any, isRedirect: any) {
    this.item = jobItem;
    this.isRedirect = isRedirect;
    console.log("isRedirect line 31: ", this.isRedirect);
    $('#popup-confirm-apply .modal').removeClass("hide");
    $('#popup-confirm-apply .modal').addClass("display");
  }

  closePopup() {
    this.item = null;
    this.isRedirect = false;
    $('#popup-confirm-apply .modal').removeClass("display");
    $('#popup-confirm-apply .modal').addClass("hide");
    this.onClose.emit();
  }

  onValidate() {
    let param = {
      item: this.item,
      isRedirect: this.isRedirect
    }
    this.validate.emit(param);
    this.closePopup();
  }
}
